// Extraer información del archivo recibido
const fileData = $input.item.binary.data;
const fileName = $input.item.json.filename || 'factura.pdf';
const fileExtension = fileName.split('.').pop().toLowerCase();
const supplierName = $input.item.json.supplier_name || null;

// Validar el archivo
if (!fileData) {
  throw new Error('No se ha proporcionado ningún archivo');
}

if (fileExtension !== 'pdf' && fileExtension !== 'jpg' && fileExtension !== 'jpeg' && fileExtension !== 'png') {
  throw new Error('Formato de archivo no soportado. Por favor, sube un PDF o una imagen (JPG, JPEG, PNG)');
}

// Preparar la salida
return {
  json: {
    fileData,
    fileName,
    fileExtension,
    supplierName,
    timestamp: new Date().toISOString()
  }
};

// Procesar la respuesta del LLM
const llmResponse = $input.item.json.text;
let datosFactura = {};
let recomendaciones = {};

// Intentar extraer el JSON si está presente
const jsonMatch = llmResponse.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch && jsonMatch[1]) {
  try {
    datosFactura = JSON.parse(jsonMatch[1]);
  } catch (error) {
    // Si hay error al parsear, usar el texto completo
    console.log('Error al parsear JSON:', error.message);
  }
}

// Extraer recomendaciones (texto fuera del JSON)
const textoSinJson = llmResponse.replace(/```json\s*[\s\S]*?\s*```/, '').trim();
recomendaciones = {
  texto: textoSinJson,
  cuentaContable: textoSinJson.match(/cuenta contable[:\s]*(\d+)/i)?.[1] || 'No especificada',
  tipoFactura: textoSinJson.match(/tipo[:\s]*([^\n.]+)/i)?.[1] || 'No especificado',
  erroresDetectados: textoSinJson.includes('error') || textoSinJson.includes('inconsistencia')
};

// Preparar datos para Odoo
const datosOdoo = {
  invoice_number: datosFactura.numeroFactura,
  invoice_date: datosFactura.fechaFactura,
  supplier_name: datosFactura.proveedor,
  supplier_vat: datosFactura.cifNif,
  amount_untaxed: datosFactura.baseImponible,
  amount_tax: datosFactura.iva?.importe || 0,
  amount_total: datosFactura.totalFactura,
  invoice_lines: datosFactura.lineasProductos?.map(linea => ({
    product_code: linea.codigo,
    name: linea.descripcion,
    quantity: linea.cantidad,
    price_unit: linea.precioUnitario
  })) || [],
  account_code: recomendaciones.cuentaContable,
  invoice_type: recomendaciones.tipoFactura
};

return {
  json: {
    success: true,
    datosFactura,
    recomendaciones,
    datosOdoo,
    analisisCompleto: llmResponse
  }
};

